"use strict";(self.webpackChunkdocs_next=self.webpackChunkdocs_next||[]).push([[62006],{3454:e=>{e.exports=JSON.parse('{"tag":{"label":"opendesk","permalink":"/docs-next/pr-preview/pr-375/docs/tags/opendesk","allTagsPath":"/docs-next/pr-preview/pr-375/docs/tags","count":3,"items":[{"id":"blueprints/by-use-case/sovereignty/opendesk/deploy-opendesk-on-cce","title":"Deploy OpenDesk on CCE","description":"This blueprint showcases how to deploy a scalable, high-availability (HA) instance of OpenDesk on T Cloud Public. Unlike the evaluation environment demonstrated in a previous guide, this production setup externalizes some services such as databases, caches and object storage onto T Cloud Public Managed Services (RDS, DCS, OBS) and uses SFS Turbo for shared filesystem access.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/deploy-opendesk-on-cce"},{"id":"blueprints/by-use-case/sovereignty/opendesk/evaluate-opendesk-on-tcloud-public","title":"Evaluate OpenDesk on T Cloud Public","description":"This blueprint walks through deploying an OpenDesk instance for evaluation and testing purposes on T Cloud Public. All databases, caches, and object storage components are deployed as containers within the cluster.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/evaluate-opendesk-on-tcloud-public"},{"id":"blueprints/by-use-case/sovereignty/opendesk/opendesk","title":"OpenDesk","description":"OpenDesk (branded as openDesk) is an open-source, sovereign digital workplace solution designed for public administration under the coordination of the German Federal Ministry of the Interior (BMI, Bundesministerium des Innern) and developed by the Centre for Digital Sovereignty of the Public Administration (ZenDiS GmbH, Zentrum f\xfcr Digitale Souver\xe4nit\xe4t der \xd6ffentlichen Verwaltung). It bundles established open-source applications into a single collaboration suite so that organisations can retain full control over their data, identities and infrastructure while avoiding dependence on large proprietary vendors.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/"}],"unlisted":false}}')}}]);